#include <bits/stdc++.h>
using namespace std;
int main(){
	int t;
	scanf("%d",&t);
	while(t--){
	    int a0,a1,b0,b1;
    	scanf("%d%d%d%d",&a0,&a1,&b0,&b1);
    	int ans=0;
    	for(int i=1;i*i<=b1;i++){
    	    if(b1%i==0){
    	        int x=i;
    	        if(__gcd(x,a0)==a1 && 1LL*b0*x/__gcd(b0,x)==b1)
    	            ans++;
    	        x=b1/i;
    	        if(x!=i && __gcd(x,a0)==a1 && 1LL*b0*x/__gcd(b0,x)==b1)
    	            ans++;
    	    }
    	}
    	printf("%d\n",ans);
    }
    
    return 0;
}
